class Solution:
    def minRemoveToMakeValid(self, s: str) -> str:
        s_list = list(s)
        stack = []

        # İlk geçiş: Eşleşmeyen ')' parantezleri belirle ve kaldır.
        # Bunları boş karakter ile işaretliyoruz.
        for i, char in enumerate(s_list):
            if char == '(':
                stack.append(i)
            elif char == ')':
                if stack:
                    stack.pop()
                else:
                    # Eşleşmeyen ')' parantezi, kaldırılacak
                    s_list[i] = '' 

        # İkinci adım: Stack'te kalan tüm '(' parantezleri eşleşmemiştir.
        # Bunları da kaldırılmak üzere işaretle.
        while stack:
            idx_to_remove = stack.pop()
            s_list[idx_to_remove] = '' 

        # İşaretlenmeyen karakterleri birleştirerek sonucu oluştur.
        return "".join(c for c in s_list if c != '')
